func:
// Simulador de Separação de Cores
const cores = ["Azul", "Verde", "Vermelho"];
const corSorteada = cores[Math.floor(Math.random() * cores.length)];

// Simulação de lógica de eficiência
const tempoCiclo = (Math.random() * (4.5 - 3.2) + 3.2).toFixed(1);
const totalProcessadas = context.get('total') || 1248;
const novoTotal = totalProcessadas + 1;
context.set('total', novoTotal);

msg.payload = {
    pecas_processadas: novoTotal,
    meta: 1500,
    eficiencia: Math.floor((novoTotal / 1500) * 100),
    tempo_ciclo: parseFloat(tempoCiclo),
    taxa_acerto: (Math.random() * (99.5 - 97.0) + 97.0).toFixed(1),
    cor_detectada: corSorteada,
    status_robo: "Operando"
};

return msg;
